import { useState } from "react";
import { Link } from "react-router-dom";

export default function LoginForm() {
  const rederErrorMessage = (name) =>
    name === errorMessages.name && (
      <div className="error">{errorMessages.message}</div>
    )

  const [errorMessages, setErrorMessages] = useState({});
  const [isSubmitted, setIsSubmitted] = useState(false);

  const database = [
    {
      username: "joao",
      password: "teste"
    },
    {
      username: "dimitri",
      password: "teste"
    }
  ]

  const errors = {
    uname: "invalid username",
    pass: "invalid password"
  }


  const handleSubmit = (event) => {
    event.preventDefault();

    let { uname, pass } = document.forms[0];

    const userData = database.find((user) => user.username === uname.value)

    if (userData) {
      if (userData.password != pass.value) {
        setErrorMessages({ name: "pass", message: errors.pass })
      } else {
        setIsSubmitted(true);
      }
    } else {
      setErrorMessages({ name: "uname", message: errors.uname })
    }
  }

  const geraForm = (
    <form onSubmit={handleSubmit}>
      <h1>Email:</h1>
      <input
        type="text"
        name="email"
        placeholder="digite seu email aqui"
        className="border border-black rounded-lg w-full mb-2 h-[50px] p-5"
        required
      />
      <h1>Senha:</h1>
      <input
        type="password"
        name="password"
        placeholder="digite sua senha aqui"
        className="border border-black rounded-lg w-full mb-2 h-[50px] p-5"
        required
      />
      <h1 className="mb-3 cursor-pointer font-bold">
        <Link to="/esqueciSenha">Esqueceu sua senha?</Link>
      </h1>
      <Link to="/conta">
          <button
            type="submit"
            className="bg-verde w-full rounded-lg h-[40px] text-branco mb-[20px]"
          >
            Entrar
          </button>
        </Link>
    </form>
  )
  return (
    <div className="bg-branco w-[30vw] h-fit p-10 rounded-lg ">
      <div>
        {isSubmitted ? <div>Usuário logado com sucesso</div> : geraForm}
      </div>


      <h1 className="text-center">
        Não tem conta?{" "}
        <Link to="/cadastro" className="text-verde font-bold">
          Criar conta
        </Link>
      </h1>
    </div>
  );
}
